VALUES
  ('optometrist-moex-01634', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關視網膜檢影鏡檢查（retinoscopy）之敘述，下列何者正確？', '["當受測者為較高近視度數者，反射光之焦點會落在檢查者視網膜檢影鏡之後方，因而造成逆動影像 （againstmovement）", "針對某些眼底反光較不易判斷的患者（如：白內障患者），些微工作距離的改變可能會造成測得屈光度 的大量誤差", "測量時檢查者應偏離受測者視軸（visualaxis），以避免殘餘散光度數過高", "造成視網膜檢影鏡誤差之主要原因為未確實控制受測者之調節，故可使用非調節性視標（特別是紅綠視 標的紅色部分）來避免調節介入而影響檢查結果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01635', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '自動電腦驗光儀針對未散瞳的兒童檢驗出的結果與需要矯正的度數相比較，最常見會有較多的下列何種度 數？', '["正鏡片的度數", "負鏡片的度數", "正圓柱鏡片的度數", "負圓柱鏡片的度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01636', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '用手動綜合驗光儀和檢影鏡驗光時，使用平行光在 67 公分處驗光發覺反射光是順動，則這患者最不可能 患有：', '["低度近視", "低度遠視", "高度近視", "高度遠視"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01637', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '為近視病人配鏡時，根據紅綠測試（duochrometest），若病人覺得綠色底的字較清楚，則代表此配鏡鏡片 如何？', '["近視度數過度矯正（overcorrection）", "近視度數矯正不足（undercorrection）", "鏡片度數正確", "顏色與鏡片度數無關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01638', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '自覺式驗光步驟測量第一眼（右眼）視力要將右眼霧視（fogging）時，將患者視力下降到多少最合適？', '["0.3～0.5", "0.01以下", "0.8～0.9", "0.01～0.1"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01639', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '使用散光鐘面圖（clockdialchart）測量散光軸時，2～8點鐘的位置線條明顯清楚，預測其負圓柱鏡的散光 軸為多少？', '["30度", "60度", "90度", "120度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01640', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '運用交叉圓柱鏡測量+6.00DS/-0.75DC×090的散光軸度時，被檢者選擇負圓柱鏡散光軸在45度，正圓柱 鏡散光軸在135度的鏡片較為清楚的時候，散光軸應先朝向那個方向調整較為正確？', '["80～75度", "90度", "100～105度", "130～135度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01641', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '運用散光鐘面圖散光測量法時，下列何者是較合適的測量起始點？', '["散光形成的最小模糊圈（circleofleastconfusion）在視網膜上", "散光形成的前主焦線（focalline）在視網膜前方，後主焦線在視網膜後方", "散光形成的兩個主焦線都在視網膜的前方", "散光形成的兩個主焦線都在視網膜的後方"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01642', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關自覺驗光利用紅綠雙色檢查法，下列敘述何者錯誤？', '["紅綠雙色常用以單獨檢查球面鏡度，不需檢影鏡或最佳球面度的協助", "檢查終點的目標是讓紅綠兩邊的視標看起來一樣清楚", "當兩邊的視標一樣清楚時，加上-0.25DS會使綠色邊的視標趨於清楚", "若無法達成紅綠兩邊的字一樣清楚，則以第一個鏡片讓綠色邊視標清楚為終點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01643', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '正視眼者，在33公分閱讀所需的老花眼鏡，其老花加入度（readingadd）大約為多少？', '["40歲+1.00D；50 歲+2.00D；60歲+3.00D", "40歲+2.00D；50 歲+3.00D；60歲+4.00D", "40歲+2.50D；50 歲+3.50D；60歲+4.50D", "40歲+3.00D；50 歲+4.00D；60歲+5.00D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "7c090ac6b7f7", "answer_pdf_sha1": "2b054529b71b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
